import { useState, useEffect } from 'react';
import axios from 'axios';

const AdminDashboard = () => {
  const [posts, setPosts] = useState([]);
  const token = localStorage.getItem('token');

  useEffect(() => {
    const fetchPosts = async () => {
      try {
        const res = await axios.get('http://localhost:5000/api/posts');
        setPosts(res.data);
      } catch (err) {
        console.log("Error loading posts");
      }
    };
    fetchPosts();
  }, []);

  const removePost = async (id) => {
    if (!window.confirm("Remove this post?")) return;
    try {
      await axios.delete(`http://localhost:5000/api/posts/${id}`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setPosts(posts.filter(p => p._id !== id));
    } catch (err) {
      alert("Unauthorized to delete.");
    }
  };

  return (
    <div style={{ padding: '30px', backgroundColor: '#fce4ec', minHeight: '100vh' }}>
      <div style={{ backgroundColor: 'white', padding: '20px', borderRadius: '20px', maxWidth: '900px', margin: '0 auto' }}>
        <h2 style={{ textAlign: 'center', color: '#880e4f' }}>Admin - All Posts</h2>
        <table style={{ width: '100%', borderCollapse: 'collapse', marginTop: '20px' }}>
          <thead>
            <tr style={{ backgroundColor: '#ff1493', color: 'white' }}>
              <th style={{ padding: '12px', textAlign: 'left' }}>TITLE</th>
              <th style={{ padding: '12px', textAlign: 'center' }}>ACTION</th>
            </tr>
          </thead>
          <tbody>
            {posts.map(post => (
              <tr key={post._id} style={{ borderBottom: '1px solid #eee' }}>
                <td style={{ padding: '12px' }}>{post.title}</td>
                <td style={{ padding: '12px', textAlign: 'center' }}>
                  <button onClick={() => removePost(post._id)} style={{ backgroundColor: '#ff4d4d', color: 'white', border: 'none', padding: '5px 15px', borderRadius: '15px', cursor: 'pointer' }}>
                    Remove
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};
